#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin

# Test: cross-model refuter wire contract + quorum/consent rules (#2556)
#
# The cross-model lane is an LLM-executed protocol that shells out to a
# user-configured ORK_ALT_MODEL_CMD; there is no runtime engine to unit-test.
# This lint guards the parts that CAN drift:
#   - the ork-cross-model-refuter/1.0 output schema parses
#   - the stub fixture emits schema-valid JSON for each real scenario, and
#     malformed output is genuinely non-JSON (so the parser forces UPHELD)
#   - the operational doc still documents the load-bearing rules:
#       * absent ORK_ALT_MODEL_CMD degrades to same-model (never "no refutation")
#       * an unverifiable citation is forced to UPHELD (engine §3)
#       * CRITICAL/HIGH ADDS the cross-model judge (3 total), not substitutes (#2556)
#       * consent is prompt-once, aligned with /ultrareview (#2556)
# No new deps — plain node -e + the stub.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"
SCHEMA="$REPO_ROOT/src/skills/review-pr/references/cross-model-output.schema.json"
STUB="$REPO_ROOT/tests/fixtures/cross-model-refuter/stub-alt-model.sh"
DOC="$REPO_ROOT/src/skills/review-pr/references/cross-model-refuter.md"
ENGINE="$REPO_ROOT/src/skills/shared/rules/adversarial-refutation.md"
ERR="$(mktemp)"
trap 'rm -f "$ERR"' EXIT

FAILED=0
pass() { echo "  PASS $1"; }
fail() { echo "  FAIL $1"; FAILED=$((FAILED + 1)); }

for f in "$SCHEMA" "$STUB" "$DOC" "$ENGINE"; do
  [[ -f "$f" ]] || { echo "FAIL: missing $f"; exit 1; }
done
[[ -x "$STUB" ]] || fail "stub fixture is not executable"

# 1. Schema parses.
if node -e 'JSON.parse(require("fs").readFileSync(process.argv[1],"utf8"))' "$SCHEMA" 2>"$ERR"; then
  pass "cross-model output schema parses"
else
  fail "schema does not parse: $(cat "$ERR")"
fi

# validator: required keys present, verdict in enum, independent_band lo<=hi, no extra keys
validate_json() {
  node -e '
    const req = ["verdict","independent_band","citation"];
    const allowed = new Set([...req,"refuter_model","rationale"]);
    const enums = ["UPHELD","DOWNGRADE","OVERTURN","KILL"];
    let s=""; process.stdin.on("data",d=>s+=d).on("end",()=>{
      let j; try { j = JSON.parse(s); } catch(e){ console.error("not json"); process.exit(1); }
      for (const k of req) if (!(k in j)) { console.error("missing "+k); process.exit(1); }
      if (!enums.includes(j.verdict)) { console.error("bad verdict "+j.verdict); process.exit(1); }
      for (const k of Object.keys(j)) if (!allowed.has(k)) { console.error("extra key "+k); process.exit(1); }
      const m = /^(\d+)-(\d+)$/.exec(j.independent_band||"");
      if (!m || +m[1] > +m[2] || +m[2] > 10) { console.error("bad band "+j.independent_band); process.exit(1); }
    });
  '
}

# 2. Real scenarios emit schema-valid JSON.
for scen in uphold kill_verifiable kill_unverifiable; do
  if echo "" | STUB_SCENARIO="$scen" bash "$STUB" | validate_json 2>"$ERR"; then
    pass "stub scenario '$scen' emits schema-valid ork-cross-model-refuter/1.0 JSON"
  else
    fail "stub scenario '$scen' invalid: $(cat "$ERR")"
  fi
done

# 3. kill_unverifiable carries citation=null (engine §3 will force UPHELD).
if echo "" | STUB_SCENARIO=kill_unverifiable bash "$STUB" | node -e 'let s="";process.stdin.on("data",d=>s+=d).on("end",()=>{const j=JSON.parse(s);process.exit(j.citation===null?0:1)})'; then
  pass "kill_unverifiable has citation=null (→ forced UPHELD by orchestrator)"
else
  fail "kill_unverifiable should carry citation=null"
fi

# 4. malformed scenario is genuinely non-JSON (parser → UPHELD).
if echo "" | STUB_SCENARIO=malformed bash "$STUB" | node -e 'let s="";process.stdin.on("data",d=>s+=d).on("end",()=>{try{JSON.parse(s);process.exit(1)}catch{process.exit(0)}})'; then
  pass "malformed scenario is non-JSON (parse failure → UPHELD)"
else
  fail "malformed scenario unexpectedly parsed as JSON"
fi

# 5. Load-bearing doc rules still present.
grep -qiE 'degrade[ds]? to the same-model lane|never to .?no refutation|absent command degrades' "$DOC" \
  && pass "doc: degrade-to-same-model rule present" \
  || fail "doc: missing degrade-to-same-model rule"

grep -qiE 'unverifiable cit|forced to UPHELD|citation=null.*UPHELD|→ UPHELD' "$DOC" \
  && pass "doc: unverifiable-citation → UPHELD rule present" \
  || fail "doc: missing citation-verify → UPHELD rule"

grep -qiE 'ADDED, not substituted|added.*#2556|2 \(kept\)' "$DOC" \
  && pass "doc: CRITICAL/HIGH ADD (3 judges) rule present (#2556)" \
  || fail "doc: missing CRITICAL/HIGH ADD rule"

grep -qiE 'Prompt once|prompt-once|AskUserQuestion.*approv|asks first' "$DOC" \
  && pass "doc: prompt-once consent present (#2556)" \
  || fail "doc: missing prompt-once consent"

grep -qiE 'CRITICAL/HIGH it is ADDED|ADDED.*3 judges' "$ENGINE" \
  && pass "engine §11: ADD-at-CRITICAL/HIGH reflected" \
  || fail "engine §11: substitution not updated for CRITICAL/HIGH"

echo ""
if [[ "$FAILED" -eq 0 ]]; then
  echo "SUCCESS: cross-model refuter contract intact"
  exit 0
else
  echo "FAILED: $FAILED cross-model refuter contract check(s)"
  exit 1
fi
